// admin-login.jsx
import axiosInstance from "../axiosConfig";
import { useFormik } from "formik";
import { useCookies } from "react-cookie";
import { useNavigate } from "react-router-dom";

export function AdminLogin() {
    const navigate = useNavigate();
    const [cookies, setCookie] = useCookies(['admin-id']);

    const formik = useFormik({
        initialValues: {
            UserId: '',
            Password: ''
        },
        onSubmit: (admin) => {
            const inputId = admin.UserId?.trim().toLowerCase();
            const inputPass = admin.Password;

            axiosInstance.get('/get-admin')
                .then(response => {
                    const admins = response.data;

                    if (Array.isArray(admins) && admins.length > 0) {
                        const match = admins.find(a =>
                            a?.UserId?.trim().toLowerCase() === inputId &&
                            a?.Password === inputPass
                        );

                        if (match && match.UserId) {
                            setCookie('admin-id', match.UserId, { path: '/' });
                            navigate('/admin-dashboard');
                            window.location.reload();
                        } else {
                            navigate('/admin-error');
                        }
                    } else {
                        alert("No admin found");
                    }
                })
                .catch(err => {
                    console.error("Error fetching admin data:", err);
                    alert("Server error, try again later");
                });
        }
    });

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ height: '60vh' }}>
            <form className="w-25" onSubmit={formik.handleSubmit}>
                <div className="text-center bi bi-person-circle"> Admin Login</div>
                <dl>
                    <dt>Admin Id</dt>
                    <dd><input type="text" name="UserId" onChange={formik.handleChange} className="form-control" /></dd>
                    <dt>Password</dt>
                    <dd><input type="password" name="Password" onChange={formik.handleChange} className="form-control" /></dd>
                </dl>
                <button className="btn btn-danger w-100">Login</button>
            </form>
        </div>
    );
}
